// clause, so that the GROUP BY becomes a nested sub-clause of the AGGREGATE.
const nestPipeAggregateGroupBy = (nodes: AstNode[]): AstNode[] => {
  const result: AstNode[] = [];
  for (const node of nodes) {
    const prev = result[result.length - 1];
    if (
      node.type === NodeType.clause &&
      node.nameKw.text === 'GROUP BY' &&
      prev &&
      prev.type === NodeType.pipe_clause &&
      prev.nameKw.text === 'AGGREGATE' &&
      !prev.groupBy
