// Promotes AGGREGATE and EXTEND tokens to RESERVED_CLAUSE when they follow the |> operator.
// See: https://cloud.google.com/bigquery/docs/reference/standard-sql/pipe-syntax
function detectPipeClauses(tokens: Token[]): Token[] {
  let prevToken = EOF_TOKEN;
  return tokens.map(token => {
    let result = token;
    if (
      token.type === TokenType.IDENTIFIER &&
      prevToken.type === TokenType.RESERVED_PIPE &&
      promotedPipeClauses.includes(token.text.toUpperCase())
